import styled from "styled-components";
import background from "../../assets/bgUsers.svg";


export const Container = styled.div`
  background: url("${background}");
  background-size: cover;
  gap: 40px;
  height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
      min-height: fit-content;

`;

export const H1 = styled.h1`
  font-style: normal;
  font-weight: bold;
  font-size: 34px;
  line-height: 40px;
  text-align: center;
  color: #ffffff;
  margin-bottom: 80px;
`;

export const Image = styled.img`
  margin-top: 30px;
`;

export const ContainerItens = styled.div`
  background: linear-gradient(
    157.44deg,
    rgba(255, 255, 255, 0.6) 0.84%,
    rgba(255, 255, 255, 0.6) 0 0.85%,
    rgba(255, 255, 255, 0.15) 100%
  );
  border-radius: 61px 61px 1px 70px;
  padding: 31px 36px;
  display: flex;
  flex-direction: column;
  justify-content: center;
 
`;



export const User = styled.li`
  display: flex;
  justify-content: space-around;
  letter-spacing: 0.592px;
  font-style: normal;
  font-weight: bold;
  font-size: 18px;
  line-height: 22px;
  color: #eeeeee;
  margin-left: 25px;
  /* padding: 5px; */

  background: rgba(255, 255, 255, 0.25);
  box-shadow: 0px 4px 4px rgba(0, 0, 0, 0.25);
  border-radius: 14px;
  width: 342px;
  height: 58px;
  border: none;
  outline: none;
  font-style: normal;
  font-weight: normal;
  font-size: 20px;
  line-height: 28px;
  align-items: center;
  margin-top: 13px;
  margin-left: 0px;

  #Lixo {
    width: 24px;
  }

  button {
    border: none;
    background: none;
    cursor: pointer;
  }
`;
